(() => {
  const items = [];
  // X 的帖子通常以 article 标签为容器
  document.querySelectorAll('article[data-testid="tweet"]').forEach(el => {
    const authorEl = el.querySelector('a[href^="/"] div[dir="ltr"] span');
    const authorNameEl = el.querySelector('a[href^="/"] div[dir="ltr"] span');
    const handleEl = el.querySelector('a[href^="/"] div[dir="ltr"]');

    // 提取作者名称
    const author = el.querySelector('[data-testid="User-Name"] a span')?.textContent?.trim() || 
                   el.querySelector('a[href^="/"] > div span')?.textContent?.trim() || '';

    // 提取用户名（handle）
    const handleLink = el.querySelector('[data-testid="User-Name"] a[href^="/"]');
    const handle = handleLink?.getAttribute('href') || '';

    // 提取内容
    const content = el.querySelector('[data-testid="tweetText"]')?.textContent?.trim() || '';

    // 提取帖子链接
    const timeEl = el.querySelector('time');
    const link = timeEl?.closest('a')?.href || '';

    // 提取点赞数
    const likeEl = el.querySelector('[data-testid="like"]');
    const likes = likeEl?.textContent?.trim() || '';

    // 提取评论数
    const replyEl = el.querySelector('[data-testid="reply"]');
    const replies = replyEl?.textContent?.trim() || '';

    if (author && content) {
      items.push({
        author: author,
        handle: handle,
        content: content,
        link: link,
        likes: likes,
        replies: replies
      });
    }
  });
  return items;
})()

